-- Step 3: Verify health
DESCRIBE DETAIL orders;
-- Check: numFiles should be low, sizeInBytes/numFiles > 100MB

// Pipeline: pl_ingest_grid_source
// Parameters:
//   load_date     String    '2026-03-07'
//   source_system String    'meters'
//   grid_region   String    'NORTH'
//   target_table  String    'raw_meter_readings'

// Step 1: Lookup activity reads region list
//   Source: a small Delta table or JSON file with regions
//   Output: [{region: 'NORTH'}, {region: 'SOUTH'}, ...]

// Step 2: ForEach activity iterates over regions
//   Items: @activity('LookupRegions').output.value
//   Is Sequential: false (run all regions in parallel)
//   Batch count: 4 (max 4 regions concurrently)

// Step 3: Inside ForEach, Execute Pipeline:
//   Pipeline: pl_ingest_meters
//   Parameters:
//     load_date: @pipeline().parameters.load_date
//     grid_region: @item().region

// Notebook nb_bronze_meters returns row count via exit()
// If Condition after the notebook:
@greater(
  int(activity('BronzeMeters').output.result.exitValue),
  100000  // Expected minimum: 100K readings per day
)
// True: proceed to Silver
// False: alert ops team (volume too low, possible source issue)

// Visual conditional column: tariff_band
// If [consumption_kwh] >= 10000 Then 'Industrial'
// Else If [consumption_kwh] >= 1000 Then 'Commercial'
// Else If [consumption_kwh] >= 0 Then 'Residential'
// Else 'Unknown'

// Generated M code:
= Table.AddColumn(#"Previous Step", "tariff_band", each
    if [consumption_kwh] >= 10000 then "Industrial"
    else if [consumption_kwh] >= 1000 then "Commercial"
    else if [consumption_kwh] >= 0 then "Residential"
    else "Unknown",
    type text)

# Fill nulls with defaults
meters.fillna({
    'region': 'UNKNOWN',
    'daily_kwh': 0.0,
    'substation_id': 'UNASSIGNED'
})

# Coalesce: use primary, fall back to secondary
scada.withColumn('power_output',
    coalesce(col('power_output_kw'), col('backup_sensor_kw'), lit(0.0))
)

# Cumulative consumption per meter (running total)
meters.withColumn('cumulative_kwh',
    sum('daily_kwh').over(
        w_meter.rowsBetween(Window.unboundedPreceding, 0)
    )
)

# 7-day moving average consumption per meter
meters.withColumn('ma_7day',
    avg('daily_kwh').over(
        w_meter.rowsBetween(-6, 0)  # current + 6 preceding
    )
)

# 30-day moving average for trend analysis
meters.withColumn('ma_30day',
    avg('daily_kwh').over(
        w_meter.rowsBetween(-29, 0)
    )
)

# Each meter's share of its substation's total consumption
meters.withColumn('pct_of_substation',
    col('daily_kwh') / sum('daily_kwh').over(
        Window.partitionBy('substation_id', 'reading_date')
    ) * 100
)
